package pl.msurvival.market;import org.bukkit.*;import org.bukkit.command.*;import org.bukkit.configuration.file.*;import org.bukkit.entity.*;import org.bukkit.event.*;import org.bukkit.event.inventory.*;import org.bukkit.inventory.*;import org.bukkit.inventory.meta.*;import org.bukkit.persistence.*;import org.bukkit.plugin.java.JavaPlugin;import java.io.*;import java.util.*;public final class MSurvivalMarket extends JavaPlugin implements Listener{private File f;private YamlConfiguration data;private NamespacedKey action;public void onEnable(){saveDefaultConfig();action=new NamespacedKey(this,"market_action");f=new File(getDataFolder(),"balances.yml");if(!f.exists())try{getDataFolder().mkdirs();f.createNewFile();}catch(Exception e){e.printStackTrace();}data=YamlConfiguration.loadConfiguration(f);Bukkit.getPluginManager().registerEvents(this,this);}public boolean onCommand(CommandSender s,Command c,String l,String[] a){String cmd=c.getName().toLowerCase(Locale.ROOT);if(cmd.equals("rynek")&&s instanceof Player p){open(p);return true;}if(cmd.equals("kasa")&&s instanceof Player p){p.sendMessage(msg("balance").replace("%money%",String.valueOf(bal(p.getName()))));return true;}if(cmd.equals("pay")&&s instanceof Player p){if(a.length<2)return true;double x=parse(a[1]);if(x<=0||bal(p.getName())<x){p.sendMessage(msg("no-money"));return true;}add(p.getName(),-x);add(a[0],x);return true;}if(cmd.equals("rynekadmin")&&s.hasPermission("msurvival.market.admin")&&a.length>=3&&a[0].equalsIgnoreCase("give")){add(a[1],parse(a[2]));return true;}return true;}private void open(Player p){Inventory inv=Bukkit.createInventory(null,27,color("&6&lRYNEK MSURVIVAL"));fill(inv);inv.setItem(11,btn(Material.BAMBOO,"&a&lSkup farm","sell_farm",List.of("&7Bambus i trzcina są wartościowe.","&aKliknij, aby sprzedać.")));inv.setItem(13,btn(Material.TRIPWIRE_HOOK,"&4&lKup Boski Klucz","buy_boski",List.of("&7Cena: &e"+getConfig().getDouble("server-shop.boski-key-price")+"$")));inv.setItem(15,btn(Material.GOLD_INGOT,"&e&lStan konta","balance",List.of("&7Masz: &e"+bal(p.getName())+"$")));p.openInventory(inv);}@EventHandler public void click(InventoryClickEvent e){if(!(e.getWhoClicked() instanceof Player p))return;if(!e.getView().getTitle().equals(color("&6&lRYNEK MSURVIVAL")))return;e.setCancelled(true);String a=act(e.getCurrentItem());if(a==null)return;if(a.equals("sell_farm")){double earn=sellAll(p);p.sendMessage(color("&aSprzedano za &e"+earn+"$"));p.closeInventory();}if(a.equals("buy_boski")){double price=getConfig().getDouble("server-shop.boski-key-price");if(bal(p.getName())<price){p.sendMessage(msg("no-money"));return;}add(p.getName(),-price);Bukkit.dispatchCommand(Bukkit.getConsoleSender(),"keyadmin give "+p.getName()+" boski 1");p.closeInventory();}if(a.equals("balance"))p.sendMessage(msg("balance").replace("%money%",String.valueOf(bal(p.getName()))));}private double sellAll(Player p){double total=0;for(String mn:getConfig().getConfigurationSection("sell").getKeys(false)){Material m;try{m=Material.valueOf(mn);}catch(Exception e){continue;}double price=getConfig().getDouble("sell."+mn);for(ItemStack it:p.getInventory().getContents())if(it!=null&&it.getType()==m){total+=it.getAmount()*price;it.setAmount(0);}}add(p.getName(),total);return total;}private ItemStack btn(Material m,String n,String a,List<String> lore){ItemStack i=new ItemStack(m);ItemMeta im=i.getItemMeta();im.setDisplayName(color(n));ArrayList<String> l=new ArrayList<>();for(String x:lore)l.add(color(x));im.setLore(l);im.getPersistentDataContainer().set(action,PersistentDataType.STRING,a);i.setItemMeta(im);return i;}private String act(ItemStack i){return i==null||!i.hasItemMeta()?null:i.getItemMeta().getPersistentDataContainer().get(action,PersistentDataType.STRING);}private void fill(Inventory inv){ItemStack g=btn(Material.BLACK_STAINED_GLASS_PANE," ","none",List.of());for(int i=0;i<inv.getSize();i++)inv.setItem(i,g);}private double bal(String p){return data.getDouble("players."+p.toLowerCase(Locale.ROOT),0);}private void add(String p,double a){data.set("players."+p.toLowerCase(Locale.ROOT),Math.max(0,bal(p)+a));save();}private double parse(String t){try{return Double.parseDouble(t);}catch(Exception e){return 0;}}private void save(){try{data.save(f);}catch(Exception e){e.printStackTrace();}}private String msg(String k){return color(getConfig().getString("messages.prefix","")+getConfig().getString("messages."+k,""));}private String color(String t){return ChatColor.translateAlternateColorCodes('&',t==null?"":t);}}
